#include <openssl/ssl.h>
#include <openssl/err.h>
#include <openssl/x509.h>
#include <stdio.h>
#include <stdlib.h>

// Initialize OpenSSL
void InitSSL() {
    SSL_library_init();
    SSL_load_error_strings();
    OpenSSL_add_all_algorithms();
}

// Create SSL context
SSL_CTX* CreateContext() {
    const SSL_METHOD *method;
    SSL_CTX *ctx;

    method = TLS_server_method();
    ctx = SSL_CTX_new(method);

    if (!ctx) {
        perror("Unable to create SSL context");
        ERR_print_errors_fp(stderr);
        exit(EXIT_FAILURE);
    }

    // Set certificate and private key
    SSL_CTX_use_certificate_file(ctx, "server.crt", SSL_FILETYPE_PEM);
    SSL_CTX_use_PrivateKey_file(ctx, "server.key", SSL_FILETYPE_PEM);

    // Verify certificate (optional)
    SSL_CTX_set_verify(ctx, SSL_VERIFY_NONE, NULL);

    // Set minimum TLS version
    SSL_CTX_set_min_proto_version(ctx, TLS1_2_VERSION);

    // Set cipher suites
    SSL_CTX_set_cipher_list(ctx, "ECDHE-RSA-AES256-GCM-SHA384:ECDHE-RSA-AES128-GCM-SHA256");

    return ctx;
}

int main() {
    int server, client;
    struct sockaddr_in addr;
    SSL_CTX *ctx;
    SSL *ssl;
    char buffer[1024];

    InitSSL();
    ctx = CreateContext();

    // Create socket
    server = socket(AF_INET, SOCK_STREAM, 0);
    addr.sin_family = AF_INET;
    addr.sin_port = htons(4433);
    bind(server, (struct sockaddr*)&addr, sizeof(addr));
    listen(server, 1);

    // Accept connection
    client = accept(server, NULL, NULL);

    // Create SSL object and associate with socket
    ssl = SSL_new(ctx);
    SSL_set_fd(ssl, client);

    // Perform TLS handshake
    if (SSL_accept(ssl) <= 0) {
        ERR_print_errors_fp(stderr);
    } else {
        printf("TLS Protocol: %s\n", SSL_get_version(ssl));
        printf("Cipher: %s\n", SSL_get_cipher(ssl));

        // Read data from client
        int bytes = SSL_read(ssl, buffer, sizeof(buffer));
        printf("Received: %.*s\n", bytes, buffer);

        // Send response
        const char *response = "HTTP/1.1 200 OK\r\nContent-Length: 13\r\n\r\nHello, TLS!\n";
        SSL_write(ssl, response, strlen(response));
    }

    SSL_shutdown(ssl);
    SSL_free(ssl);
    close(client);
    close(server);
    SSL_CTX_free(ctx);

    return 0;
}
